const now = new Date();
const threeDaysAgo = new Date(now - 3 * 24 * 60 * 60 * 1000);

const staleDeals = items.filter(item => {
  const lastModified = new Date(item.json.properties?.hs_lastmodifieddate || 0);
  const lastContacted = new Date(item.json.properties?.notes_last_contacted || 0);
  const mostRecentActivity = lastContacted > lastModified ? lastContacted : lastModified;
  return mostRecentActivity < threeDaysAgo;
});

return staleDeals.map(item => ({
  json: {
    dealId: item.json.id,
    dealName: item.json.properties?.dealname || 'Unknown Deal',
    ownerId: item.json.properties?.hubspot_owner_id,
    closeDate: item.json.properties?.closedate,
    lastActivity: item.json.properties?.hs_lastmodifieddate,
    dealAmount: parseFloat(item.json.properties?.amount || 0),
    associatedContactId: item.json.associations?.contacts?.results?.[0]?.id || null
  }
}));

// Merge contact data back onto the deal item
const deal = $('Filter Stale Deals').item.json;
const contact = $input.item.json;

return [{
  json: {
    ...deal,
    prospectEmail: contact.properties?.email || null,
    prospectFirstName: contact.properties?.firstname || 'there',
    prospectLastName: contact.properties?.lastname || '',
    optedOut: contact.properties?.hs_email_optout === 'true' || contact.properties?.hs_email_optout === true
  }
}];

// Count how many follow-ups have already been sent for this deal
const rows = $input.all();
const followUpCount = rows.filter(r => r.json['Deal ID'] && r.json['Action'] === 'Follow-Up Email Sent').length;
const deal = $('Opted Out or No Email?').item.json;

return [{
  json: {
    ...deal,
    followUpCount,
    maxReached: followUpCount >= 3
  }
}];

