// Capture error details from any failed node
const error = $execution?.error || {};
const lastNode = error.node?.name || 'Unknown node';
const errorMessage = error.message || 'No message available';
const dealContext = $('Check Follow-Up Count')?.item?.json?.dealName || 'Unknown deal';

return [{
  json: {
    failedNode: lastNode,
    errorMessage,
    dealContext,
    timestamp: new Date().toISOString()
  }
}];

